#include<bits/stdc++.h>
using namespace std;
struct node
{
    int id,rk;
    long long val;
    bool operator<(const node&b)const
    {
        return val<b.val;
    }
};
priority_queue<node> q;
long long ans=1,x,s[20000010];
int a[20000010][2],siz[20000010],n,m,tot;
void insert(long long x)
{
    int p=0;
    for(int i=31;i>=0;i--)
    {
        int k=(x>>i)&1;
        siz[p]++;
        if(!a[p][k])
        {
            a[p][k]=++tot;
        }
        p=a[p][k];
    }
    siz[p]++;
}
long long query(long long x,long long rk)
{
    int p=0;
    long long ans=0;
    for(int i=31;i>=0;i--)
    {
        int k=(x>>i)&1;
        if(!a[p][k^1])
        {
            p=a[p][k];
        }
        else if(rk<=siz[a[p][k^1]])
        {
            p=a[p][k^1];
            ans|=(1ll<<i);
        }
        else
        {
            rk-=siz[a[p][k^1]];
            p=a[p][k];
        }
    }
    return ans;
}
int main()
{
    scanf("%d%d",&n,&m);
    m*=2;
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        s[i]=s[i-1]^x;
    }
    for(int i=0;i<=n;i++)
    {
        insert(s[i]);
    }
    for(int i=0;i<=n;i++)
    {
        q.push((node){i,1,query(s[i],1)});
    }
    for(int i=1;i<=m;i++)
    {
        node t=q.top();
        ans+=t.val;
        q.pop();
        if(t.rk<n)
        {
            q.push((node){t.id,t.rk+1,query(s[t.id],t.rk+1)});
        }
    }
    ans/=2;
    printf("%lld",ans);
    return 0;
}
